props.extensibilityCode:
// Toggle de formatação com tracking
const [isBold, setIsBold] = useState(false);

<Toggle
  pressed={isBold}
  onPressedChange={(next) => {
    track('field_change', {
      component: 'toggle',
      field_name: 'bold',
      value: String(next),
    });
    setIsBold(next);
  }}
  aria-label="Negrito"
>
  <Bold aria-hidden="true" />
</Toggle>

tokens.customizationCode:
/* Cor customizada do estado ativo */
.toggle-brand[data-state="on"] {
  @apply bg-blue-500 text-white;
}

/* Override do tamanho via tokens */
[data-slot="toggle"][data-size="default"] {
  --height-default: 2.5rem;
}

